```typescript
// 定义一个联合类型，每个成员都有一个共同的 "kind" 属性作为判别字段
type Shape =
  | { kind: "circle"; radius: number }
  | { kind: "rectangle"; width: number; height: number }
  | { kind: "triangle"; base: number; height: number };

// 利用 discriminated union 做类型收窄
function area(s: Shape): number {
  switch (s.kind) {
    case "circle":
      // 这里 s 被收窄为 { kind: "circle"; radius: number }
      return Math.PI * s.radius ** 2;
    case "rectangle":
      // s 被收窄为 { kind: "rectangle"; width: number; height: number }
      return s.width * s.height;
    case "triangle":
      // s 被收窄为 { kind: "triangle"; base: number; height: number }
      return (s.base * s.height) / 2;
  }
}

// 如果有新增类型但忘了处理，TypeScript 会报错（配合 never 做 exhaustiveness check）
function assertNever(x: never): never {
  throw new Error("Unexpected shape: " + x);
}

function areaSafe(s: Shape): number {
  switch (s.kind) {
    case "circle":
      return Math.PI * s.radius ** 2;
    case "rectangle":
      return s.width * s.height;
    case "triangle":
      return (s.base * s.height) / 2;
    default:
      return assertNever(s); // 如果 Shape 新增了成员但没加 case，编译报错
  }
}
```

**核心要点：**

- 所有成员共享同一个字面量字段（这里叫 `kind`），每个成员的该字段值唯一。
- TypeScript 在 `switch` 或 `if` 判断 `kind` 后，自动收窄类型，不用手动断言。
- `assertNever` 是可选但推荐的做法：当 `Shape` 新增变体时，遗漏的 `case` 会导致编译错误，而不是留到运行时崩。

